module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);
reg [31:0] yout_r;
reg [15:0] areg, breg;
reg [4:0] i;
reg done_r;
assign yout = yout_r;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) i <= 5'd0;
    else if(start && i<5'd17) i<= i+1;
    else i<=5'd0;
end
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) done_r <= 1'b0;
    else if(i==5'd16) done_r <= 1'b1;
    else if(i==5'd17) done_r <= 1'b0;
end
assign done = done_r;
always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        areg <= 16'b0;
        breg <= 16'b0;
        yout_r <= 32'b0;
    end
    else if(start) begin
        if(i==5'd0) begin
            areg <= ain;
            breg <= bin;
        end
        else if(i>5'd0 && i<5'd17) begin
            if(areg[i-1]) yout_r <= (yout_r + (breg << (i-1))) ;
        end
    end
end
endmodule
